sql:
SELECT AVG(temperature) AS average_temperature, MAX(total_energy) AS max_energy_produced
FROM panel_data
WHERE panel_id = 1;

SELECT DISTINCT panel_id
FROM panel_data
WHERE time LIKE '2023-03-%';

SELECT reduced_co2
FROM environmental_impact
WHERE panel_id = 1;

external_knowledge:
- "Blossoming with energy since the new decade" refers to solar panels installed in or after the year 2020; 
- "Blooming with energy in the past year" refers to the time range between '2023-01-01 00:00:00' and '2023-12-31 23:59:59'; 
- "Leaving a footprint" refers to the average total energy produced; 
- "Making an impact on CO2 reduction" refers to the average reduced CO2.

sql:
SELECT location, capacity_kw
FROM solar_panels
ORDER BY capacity_kw DESC;

SELECT SUM(capacity_kw) AS total_capacity
FROM solar_panels
WHERE location = 'New York';
